async fn bytes_limited() {
    let (body, headers) = create_double_request_with_header();

    let mut multipart = Multipart::new(&headers, stream::iter([Ok(body)]));

    multipart
        .next()
        .await
        .expect("multipart should have two fields")
        .expect("multipart body should be well formatted")
        .bytes(8) // smaller than data size
        .await
        .expect_err("field data should be size limited");

    // next field still readable
    let field = multipart
        .next()
        .await
        .expect("multipart should have two fields")
        .expect("multipart body should be well formatted")
        .bytes(usize::MAX)
        .await
        .expect("field data should not be size limited")
        .expect("reading field data should not error");
    assert_eq!(field, "two+two+two");
}

fn terminal_mode_guard_acquire_and_drop() {
  // Should not panic whether or not a console is attached (in CI stdin is
  // typically redirected, so the captured mode is `None` and restoring is a
  // no-op). On a real console it captures and restores the mode. The guard
  // is restored when it goes out of scope at the end of this block, and the
  // captured snapshot can be restored eagerly any number of times.
  {
    let guard = TerminalModeGuard::acquire();
    let saved = guard.saved();
    saved.restore();
    saved.restore();
  }
  SavedTerminalMode::capture().restore();
}

fn wake_specific_thread(&self, index: usize) -> bool {
    let sleep_state = &self.worker_sleep_states[index];

    let mut is_blocked = sleep_state.is_blocked.lock().unwrap();
    if *is_blocked {
        *is_blocked = false;
        sleep_state.condvar.notify_one();

        // When the thread went to sleep, it will have incremented
        // this value. When we wake it, its our job to decrement
        // it. We could have the thread do it, but that would
        // introduce a delay between when the thread was
        // *notified* and when this counter was decremented. That
        // might mislead people with new work into thinking that
        // there are sleeping threads that they should try to
        // wake, when in fact there is nothing left for them to
        // do.
        self.counters.sub_sleeping_thread();

        true
    } else {
        false
    }
}

fn check_data(self) {
    // Using a block `{self.data}` here to force a copy instead of using `self.data`
    // directly, because `debug_assert_eq` takes references to its arguments and formatting
    // arguments and would thus borrow `self.data`. Since `Self`
    // is a packed struct, that would create a possibly unaligned reference, which
    // is UB.
    debug_assert_eq!(
        self.size().truncate(self.data),
        { self.data },
        "Scalar value {:#x} exceeds size of {} bytes",
        { self.data },
        self.size
    );
}

pub(super) unsafe fn spawn_in<F>(func: F, registry: &Arc<Registry>)
where
    F: FnOnce() + Send + 'static,
{
    // We assert that this does not hold any references (we know
    // this because of the `'static` bound in the interface);
    // moreover, we assert that the code below is not supposed to
    // be able to panic, and hence the data won't leak but will be
    // enqueued into some deque for later execution.
    let abort_guard = unwind::AbortIfPanic; // just in case we are wrong, and code CAN panic
    let job_ref = unsafe { spawn_job(func, registry) };
    registry.inject_or_push(job_ref);
    mem::forget(abort_guard);
}

pub fn register_type_outlives_constraint(&self, sup_type: Ty<'db>, sub_region: Region<'db>) {
    // `is_global` means the type has no params, infer, placeholder, or non-`'static`
    // free regions. If the type has none of these things, then we can skip registering
    // this outlives obligation since it has no components which affect lifetime
    // checking in an interesting way.
    if sup_type.is_global() {
        return;
    }

    debug!(?sup_type, ?sub_region);

    self.register_type_outlives_constraint_inner(TypeOutlivesConstraint {
        sup_type,
        sub_region,
    });
}

